const item = $input.first().json;

try {
  const summary = item.invoiceSummary || {};
  const lineItems = Array.isArray(summary.lineItems) ? summary.lineItems : [];

  // Defensive: fall back gracefully if any expected field is missing
  const fmt = (n) => (typeof n === 'number' ? n.toFixed(2) : String(n ?? '?'));
  const currency = summary.currency || '???';

  const lineItemsText = lineItems.length > 0
    ? lineItems.map(li => '• ' + (li.description || '(no description)') + ' — ' + currency + ' ' + fmt(li.amount) + ' (' + (li.accountName || 'unknown account') + ')').join('\n')
    : '(no line items provided)';

  const approvalMessage = '*AP Invoice Approval Required*\n\n' +
    '*Vendor:* ' + (summary.vendorName || 'unknown') + ' (hash: ' + (summary.vendorIdHash || 'n/a') + ')\n' +
    '*Invoice:* ' + (summary.invoiceNumber || 'n/a') + '\n' +
    '*Date:* ' + (summary.invoiceDate || 'n/a') + '\n' +
    '*Total:* ' + currency + ' ' + fmt(summary.totalAmount) + '\n\n' +
    '*Why this needs review:* ' + (item.reviewReason || 'no reason given') + '\n\n' +
    '*Submitted by:* ' + (item.submittedBy || 'unknown') + '\n\n' +
    '*Line items:*\n' + lineItemsText + '\n\n' +
    '*Audit log:* ' + (item.auditLogEntryId || 'n/a');

  return [{
    json: {
      ...item,
      approvalMessage: approvalMessage,
      _summaryBuiltAt: new Date().toISOString()
    }
  }];

} catch (err) {
  // If summary build fails, still proceed with a fallback message — the approver should always see SOMETHING
  return [{
    json: {
      ...item,
      approvalMessage: 'AP Invoice Approval Required (summary build failed: ' + err.message + ') — see audit log ' + (item.auditLogEntryId || 'n/a'),
      _summaryBuildError: err.message
    }
  }];
}

// Workflow 03's Execute Workflow Trigger returns whatever the last node emits.
// Slack: Notify Decision is upstream — its chat.postMessage response is NOT what the orchestrator needs.
// This node re-emits the decision contract built by the branch's Build *Response node.
function safeNode(name) {
  try {
    const ref = $(name);
    if (!ref || typeof ref.first !== 'function') return null;
    const first = ref.first();
    if (!first || !first.json) return null;
    const keys = Object.keys(first.json);
    if (keys.length === 0) return null;
    return first.json;
  } catch (e) {
    return null;
  }
}

const approved = safeNode('Build APPROVED Response');
const rejected = safeNode('Build REJECTED Response');
const timedOut = safeNode('Build TIMEOUT Response');

const contract = approved || rejected || timedOut;
if (contract && contract.decision) {
  return [{ json: contract }];
}

// Defensive: no branch's Build *Response produced data. Return a structured error
// so the orchestrator can route this to Update Audit Log: FAILED rather than blindly post.
let auditLogEntryId = null;
try { auditLogEntryId = $('When Called by Orchestrator').first().json.auditLogEntryId || null; } catch (e) {}
return [{
  json: {
    decision: 'UNKNOWN',
    error: 'WF03 did not produce a decision contract — investigate the Switch: Decision branch routing',
    auditLogEntryId
  }
}];
